import re

@dataclass
class SEORequirements:
    primary_keyword: str         # must appear in title and first 100 words
    secondary_keywords: list[str]
    target_density: float = 0.015  # 1.5% — keyword appears ~once per 67 words


def check_seo(
    text: str,
    seo: SEORequirements,
) -> dict:
    word_count = len(text.split())
    text_lower = text.lower()

    primary_count = text_lower.count(seo.primary_keyword.lower())
    primary_density = primary_count / word_count if word_count else 0

    secondary_counts = {
        kw: text_lower.count(kw.lower()) for kw in seo.secondary_keywords
    }
    in_title = seo.primary_keyword.lower() in text_lower.split("\n")[0].lower()
    first_100 = " ".join(text.split()[:100]).lower()
    in_intro = seo.primary_keyword.lower() in first_100

    issues = []
    if not in_title:
        issues.append(f"Primary keyword '{seo.primary_keyword}' missing from title")
    if not in_intro:
        issues.append(f"Primary keyword missing from first 100 words")
    if primary_density < seo.target_density * 0.5:
        issues.append(f"Keyword density {primary_density:.1%} too low (target ~{seo.target_density:.1%})")
    if primary_density > seo.target_density * 2:
        issues.append(f"Keyword density {primary_density:.1%} too high (may trigger over-optimization)")
    for kw, count in secondary_counts.items():
        if count == 0:
            issues.append(f"Secondary keyword '{kw}' not found")

    return {
        "word_count": word_count,
        "primary_density": primary_density,
        "secondary_found": secondary_counts,
        "in_title": in_title,
        "in_intro": in_intro,
        "issues": issues,
        "passes": len(issues) == 0,
    }


def fix_seo_issues(text: str, issues: list[str], seo: SEORequirements) -> str:
    """Ask the model to fix specific SEO issues without full regeneration."""
    if not issues:
        return text
    issues_str = "\n".join(f"- {i}" for i in issues)
    prompt = (
        f"The following article has these SEO issues that need to be fixed:\n{issues_str}\n\n"
        f"Primary keyword: '{seo.primary_keyword}'\n"
        f"Secondary keywords: {', '.join(seo.secondary_keywords)}\n\n"
        "Fix ONLY the SEO issues. Do not change the substance, structure, or style of the content. "
        "Return the full corrected article."
    )
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=8192,
        messages=[
            {"role": "user", "content": prompt},
            {"role": "assistant", "content": text},
            {"role": "user", "content": "Please apply the fixes now."},
        ],
    )
    return response.content[0].text
